async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const searchInput = await browser.extractComponent<{ cssSelector: string; submitButtonCssSelector: string }>({
        typeName: 'SearchInput',
        schema: '{ cssSelector: string; submitButtonCssSelector: string; }'
    }, params.restaurantName);
    if (!searchInput || !searchInput.cssSelector) {
        throw new Error('Could not find search input on this page');
    }
    await browser.clearAndType(searchInput.cssSelector, params.restaurantName);
    if (searchInput.submitButtonCssSelector) {
        await browser.clickAndWait(searchInput.submitButtonCssSelector);
    } else {
        await browser.pressKey('Enter');
        await browser.awaitPageLoad();
    }

    const restaurant = await browser.extractComponent<{ restaurantName: string; detailsLinkSelector: string }>({
        typeName: 'RestaurantResult',
        schema: '{ restaurantName: string; rating: string; detailsLinkSelector: string; }'
    }, params.restaurantName);
    if (!restaurant || !restaurant.detailsLinkSelector) {
        throw new Error('Could not find restaurant: ' + params.restaurantName);
    }
    await browser.clickAndWait(restaurant.detailsLinkSelector);

    const reservations = await browser.extractComponent<{ date: string; availableTimeSlots?: { time?: string; cssSelector: string }[] }>({
        typeName: 'BookReservationsModule',
        schema: '{ date: string; targetTime: string; availableTimeSlots?: { time?: string; cssSelector: string; }[]; numberOfPeople?: number; }'
    });
    if (!reservations || !reservations.availableTimeSlots || reservations.availableTimeSlots.length === 0) {
        return { success: false, error: 'No available time slots found for ' + params.restaurantName };
    }
    const times = reservations.availableTimeSlots.map(s => s.time).filter(Boolean).join(', ');
    return { success: true, message: 'Available times at ' + params.restaurantName + ': ' + times, data: reservations };
}
